VALUES
  ('police-b20a8cf8-moex-00104', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於司法警察攜帶警械於管轄區外執行搜索、逮捕或拘提等行動時之說明，何者錯誤？', '["通報當地警察機關知悉或會同辦理", "如臨時變更地點，可不必通知原會同及變更擬往地點之警察機關或通報當地警察局或分局勤務 指揮中心", "接受請求會同辦案之警察機關，應即通報所屬刑警大隊（隊）、分局及分駐所或派出所，並派 員協同辦理", "相關通報程序及其規定應依各級警察機關通報越區辦案應行注意要點辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00105', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於在刑案現場逮捕犯罪嫌疑人應注意事項之說明，何者錯誤？', '["於刑案現場以外之處所逮捕犯罪嫌疑人時，應立即帶回現場", "得使用警械防止其脫逃", "犯罪嫌疑人攜帶或藏放之武器，應立即扣押或留存，並記錄其外觀及所在位置", "記錄犯罪嫌疑人自發性之供述、身上形跡及任何不正常之舉止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00106', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察機關對重大及特殊刑案，係由何機關列管督導考核？', '["縣市警察局", "各分局", "警政署刑事警察局", "內政部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00107', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於刑法竊盜罪相關規定之說明，何者正確？', '["犯竊盜罪因防護贓物，而當場施以強暴脅迫者，以強盜論", "竊取電能不構成竊盜罪", "直系血親間，犯竊盜章之罪者，加重其刑", "五親等內姻親間，犯竊盜章之罪者，須告訴乃論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00108', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列何者不屬於偵查中辯護人之權限？', '["檢閱、抄錄或攝影卷宗及證物", "詢問完畢後令犯罪嫌疑人閱覽筆錄時，協助閱覽", "無刑事訴訟法第245條第2項但書情形，得於司法警察詢問犯罪嫌疑人時在場", "證人指認犯罪嫌疑人時，該犯罪嫌疑人之辯護人得在場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00109', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '16 歲中學生甲暑假打工，因工作輕鬆賺錢快而擔任詐騙集團車手，於某次與已成年之同夥乙至 外縣市收取被害人款項之際，遭埋伏警察依現行犯逮捕，試問下列關於本案之處理，何者正確？', '["甲觸犯刑法第339條之4第1項第2款加重詐欺罪，依少年事件處理法之相關規定，應移送至 少年住所、居所或所在地之少年法院或地方法院設少年法庭", "甲於警詢中供述，其國小甫畢業12歲之鄰居丙亦是詐騙集團車手，因故此次一同前來。警查 獲知上情後，得依刑事訴訟法第88條之1逕行拘提丙", "警察機關於詢問甲時，基於保護少年刑事犯罪人，不論有無合理原因或是否情況急迫，均應通 知甲之法定代理人、現在保護少年之人或其他適當之人陪同在場", "少年甲遭逮捕後，送回警局已是夜間11時，惟仍得針對甲之姓名、年齡、籍貫、職業、住居 所等進行詢問，以查驗其人有無錯誤"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00110', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '近來遇有重大案件，報紙媒體大肆追蹤報導，甚至成為政論節目熱門話題，「偵查不公開」再度 引起討論。下列有關「偵查不公開作業辦法」之敘述何者錯誤？', '["檢察官、檢察事務官、司法警察官、司法警察、辯護人、告訴代理人或其他於偵查程序依法執 行職務之人員應遵守「偵查不公開」義務", "被告雖非「偵查不公開」規範對象，惟檢察官、司法警察人員得曉示被告如公開或揭露偵查中 所知悉程序或內容對案件之可能影響。實務上尚且包括檢察官得按刑事訴訟法有串證之虞，向 法院聲請羈押", "依偵查不公開作業辦法，基於公共利益之維護或合法權益之保護，除法律另有規定外，必要時，偵 查機關或偵查輔助機關得適度公開或揭露被告、少年或犯罪嫌疑人之具體供述及是否自首或自白", "檢察官偵查終結，依法提起公訴，案件已繫屬法院時，即無「偵查不公開」原則之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00111', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依據「警察偵查犯罪手冊」及「刑事鑑識手冊」之規定，下列有關記錄跡證之敘述何者錯誤？', '["槍枝應視個案情況及必要性，採取指紋、射擊殘跡或生物跡證等，如有同時採取二種以上跡證 之需要時，採證之順序以便利為原則", "刑案現場採證標的，包括因犯罪所遺留或遺棄之物，如嫌犯遺留之包裝紙，菸蒂，口香糖殘渣等", "警察人員實施刑案現場保全，進入現場者，須著必要之防護裝備（如帽套、手套、鞋套等）， 以免破壞現場跡證", "有關火（炸）藥及爆炸遺留物之處理原則，爆炸點周遭疑為火（炸）藥附著物，宜全部採集送驗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00112', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列何者不屬於警察偵查犯罪手冊規定所列舉辦理警政署刑案資料之查詢、提供及運用時，應遵 守之法令？', '["個人資料保護法", "民事訴訟法", "少年事件處理法", "警察刑事紀錄證明核發條例"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00113', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列案件被告，何者於偵查中未經選任辯護人者，司法警察官或司法警察應通知依法設立之法律 扶助機構指派律師到場為其辯護？', '["吸食大麻後打傷路人而無法完全陳述之外國人", "與朋友共同犯重傷害罪之原住民青年", "酒後妨害公務並打傷外國駐台代表兒子的大學生", "誹謗退休後居住於我國之前外國駐台代表之候選人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
